const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles_state') || '[]');
const searchQueries = JSON.parse(localStorage.getItem('search_queries') || '[]');

// Find candidate 4K streaming articles in Watching on TV > Streaming issues
const keywordRegex = /4k/i;
const candidateArticles = articles.filter(a => {
  const text = `${a.title || ''} ${a.summary || ''} ${a.body || ''}`;
  return a.category_code === 'watching_on_tv'
    && a.subcategory_id === 'watching_on_tv_streaming_issues'
    && keywordRegex.test(text);
});

// Identify the most recently updated candidate article
let mostRecent = null;
if (candidateArticles.length > 0) {
  mostRecent = candidateArticles.reduce((best, cur) => {
    if (!best) return cur;
    const bestTime = best.last_updated_at ? Date.parse(best.last_updated_at) : 0;
    const curTime = cur.last_updated_at ? Date.parse(cur.last_updated_at) : 0;
    return curTime > bestTime ? cur : best;
  }, null);
}

const savedMostRecent = !!(mostRecent && saved.some(sa => sa.article_id === mostRecent.id));

// CP1 (0.7): User saved the correct most recently updated 4K streaming article in the TV streaming issues section
checkpoints.push({ passed: !!mostRecent && savedMostRecent, weight: 0.7 });

// CP2 (0.3): User performed a search for 4K with Streaming quality topic, sorted by newest, that returned this article
let searched4KWithFilters = false;
if (mostRecent) {
  searched4KWithFilters = searchQueries.some(q => {
    if (!q || typeof q.query_text !== 'string') return false;
    const has4k = /4k/i.test(q.query_text);
    const hasStreamingQuality = Array.isArray(q.topic_filter_codes) && q.topic_filter_codes.includes('streaming_quality');
    const correctSort = q.sort_by === 'last_updated_newest';
    const includesArticle = Array.isArray(q.result_article_ids) && q.result_article_ids.includes(mostRecent.id);
    return has4k && hasStreamingQuality && correctSort && includesArticle;
  });
}

checkpoints.push({ passed: !!mostRecent && searched4KWithFilters, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const supportRequests = JSON.parse(localStorage.getItem('support_requests') || '[]');
const contactOptions = JSON.parse(localStorage.getItem('contact_options') || '[]');

// Identify the smart TV buffering article dynamically
const smartTvArticles = articles.filter(a => {
  const text = `${a.title || ''} ${a.summary || ''}`.toLowerCase();
  const isTvStreamingIssues = a.category_code === 'watching_on_tv' && a.subcategory_id === 'watching_on_tv_streaming_issues';
  const mentionsSmartTv = text.includes('smart tv');
  const mentionsBufferingOrQuality = text.includes('buffering') || text.includes('poor video quality') || text.includes('video quality');
  return isTvStreamingIssues && mentionsSmartTv && mentionsBufferingOrQuality;
});
const smartArticle = smartTvArticles[0] || null;

// Determine fastest available contact methods for that article
let fastestTypes = new Set();
if (smartArticle) {
  const opts = contactOptions.filter(co => co.article_id === smartArticle.id && co.available !== false);
  if (opts.length > 0) {
    let minWait = Infinity;
    opts.forEach(o => {
      const wait = typeof o.estimated_wait_minutes === 'number' ? o.estimated_wait_minutes : Infinity;
      if (wait < minWait) minWait = wait;
    });
    opts.forEach(o => {
      const wait = typeof o.estimated_wait_minutes === 'number' ? o.estimated_wait_minutes : Infinity;
      if (wait === minWait) fastestTypes.add(o.type);
    });
  }
}

// Requests from that article with correct topic and fastest contact method
let basicRequests = [];
if (smartArticle && fastestTypes.size > 0) {
  basicRequests = supportRequests.filter(r => {
    if (!r) return false;
    if (r.source_article_id !== smartArticle.id) return false;
    if (r.topic !== 'streaming_quality') return false;
    if (!fastestTypes.has(r.contact_method)) return false;
    return true;
  });
}

// Among those, check description mentions buffering and around 8 PM
const correctRequests = basicRequests.filter(r => {
  const desc = (r.description || '').toLowerCase();
  const mentionsBuffer = desc.includes('buffer');
  const mentions8pm = /8\s*pm/i.test(r.description || '');
  return mentionsBuffer && mentions8pm;
});

// CP1 (0.5): Submitted from the smart TV buffering article with Streaming quality topic using the fastest contact method
checkpoints.push({ passed: basicRequests.length > 0, weight: 0.5 });

// CP2 (0.5): That request's description clearly mentions buffering around 8 PM
checkpoints.push({ passed: correctRequests.length > 0, weight: 0.5 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const sections = JSON.parse(localStorage.getItem('article_sections') || '[]');
const feedback = JSON.parse(localStorage.getItem('article_feedback') || '[]');

// Find cancellation articles in the 'Canceling your subscription' subcategory
const cancelArticles = articles.filter(a => a.subcategory_id === 'canceling_your_subscription');

// Compute total instruction steps per article
const stepInfo = cancelArticles.map(a => {
  const instrSections = sections.filter(s => s.article_id === a.id && s.type === 'instructions');
  const totalSteps = instrSections.reduce((sum, s) => {
    if (typeof s.step_count === 'number') return sum + s.step_count;
    if (Array.isArray(s.step_texts)) return sum + s.step_texts.length;
    return sum;
  }, 0);
  return { articleId: a.id, steps: totalSteps };
});

// Determine which article is simpler (fewest steps)
let simplerArticleId = null;
if (stepInfo.length > 0) {
  const simplest = stepInfo.reduce((best, cur) => {
    if (!best) return cur;
    return cur.steps < best.steps ? cur : best;
  }, null);
  if (simplest) simplerArticleId = simplest.articleId;
}

// Look for a new helpful vote on the simpler article on or after 2026-03-03
const thresholdDate = '2026-03-03T00:00:00Z';
const helpfulOnSimpler = simplerArticleId && feedback.some(f => {
  if (!f || f.article_id !== simplerArticleId) return false;
  if (!f.helpful) return false;
  if (!f.created_at) return false;
  return f.created_at >= thresholdDate;
});

// CP1 (1.0): User marked the simpler cancellation article as helpful (new feedback in current session window)
checkpoints.push({ passed: !!simplerArticleId && helpfulOnSimpler, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const articleTopics = JSON.parse(localStorage.getItem('article_topics') || '[]');
const articleDeviceSupport = JSON.parse(localStorage.getItem('article_device_support') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles_state') || '[]');

// Determine Android + subtitles/captions/audio articles dynamically
const topicCode = 'subtitles_captions_audio';
const deviceCode = 'android_phone_tablet';

const topicArticleIds = new Set(
  articleTopics
    .filter(t => t && t.topic_code === topicCode)
    .map(t => t.article_id)
);

const deviceArticleIds = new Set(
  articleDeviceSupport
    .filter(d => d && d.device_code === deviceCode)
    .map(d => d.article_id)
);

let candidateArticles = articles.filter(a => topicArticleIds.has(a.id) && deviceArticleIds.has(a.id));

// Fallback: if device mapping is missing, use title/summary heuristics for Android subtitles
if (candidateArticles.length === 0) {
  candidateArticles = articles.filter(a => {
    const text = `${a.title || ''} ${a.summary || ''}`.toLowerCase();
    return text.includes('android') && (text.includes('subtitles') || text.includes('audio language'));
  });
}

// Choose highest-rated article among candidates (tie-breaker: higher rating_count)
let bestArticle = null;
if (candidateArticles.length > 0) {
  bestArticle = candidateArticles.reduce((best, cur) => {
    if (!best) return cur;
    const ra = typeof cur.average_rating === 'number' ? cur.average_rating : 0;
    const rb = typeof best.average_rating === 'number' ? best.average_rating : 0;
    if (ra !== rb) return ra > rb ? cur : best;
    const ca = typeof cur.rating_count === 'number' ? cur.rating_count : 0;
    const cb = typeof best.rating_count === 'number' ? best.rating_count : 0;
    return ca > cb ? cur : best;
  }, null);
}

// Check that this highest-rated article was saved
const savedHighest = !!(bestArticle && saved.some(sa => sa.article_id === bestArticle.id));

// Read instrumentation variable for viewing the article in Spanish
let viewedRecord = null;
const rawViewed = localStorage.getItem('task4_androidSubtitlesArticleViewedEs');
if (rawViewed) {
  try {
    viewedRecord = JSON.parse(rawViewed);
  } catch (e) {
    viewedRecord = null;
  }
}

const viewedEsCorrect = !!(bestArticle && viewedRecord && viewedRecord.articleId === bestArticle.id && viewedRecord.language === 'es');

// CP1 (0.6): User saved the highest-rated Android subtitles/audio article
checkpoints.push({ passed: !!bestArticle && savedHighest, weight: 0.6 });

// CP2 (0.4): User viewed that same article in Spanish (language 'es') per instrumentation
checkpoints.push({ passed: !!bestArticle && viewedEsCorrect, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles_state') || '[]');

// Find parental controls articles appropriate for teen maturity ratings in the parental controls subcategory
const teenMaturityArticles = articles.filter(a => {
  const inParentalSubcat = a.category_code === 'account_profiles' && a.subcategory_id === 'parental_controls_and_pins';
  const hasTeens = Array.isArray(a.applicable_maturity_levels) && a.applicable_maturity_levels.includes('teens');
  const text = `${a.title || ''} ${a.summary || ''} ${a.body || ''}`.toLowerCase();
  const mentionsMaturity = text.includes('maturity') || text.includes('rating');
  return inParentalSubcat && hasTeens && mentionsMaturity;
});

const teenArticleIds = new Set(teenMaturityArticles.map(a => a.id));

// Check if at least one such teen maturity article was saved
const savedTeenMaturity = saved.some(sa => teenArticleIds.has(sa.article_id));

// Identify PIN-related parental controls articles
const pinArticles = articles.filter(a => {
  const inParentalSubcat = a.category_code === 'account_profiles' && a.subcategory_id === 'parental_controls_and_pins';
  const text = `${a.title || ''} ${a.summary || ''} ${a.body || ''}`.toLowerCase();
  return inParentalSubcat && text.includes('pin');
});
const pinArticleIds = new Set(pinArticles.map(a => a.id));

// Read instrumentation variable for opening a PIN restrictions article
let openedPin = null;
const rawOpened = localStorage.getItem('task5_openedPinRestrictionsArticle');
if (rawOpened) {
  try {
    openedPin = JSON.parse(rawOpened);
  } catch (e) {
    openedPin = null;
  }
}

const openedPinIsRelated = !!(openedPin && pinArticleIds.has(openedPin.articleId));

// CP1 (0.5): User saved at least one teen-focused maturity rating parental controls article
checkpoints.push({ passed: savedTeenMaturity, weight: 0.5 });

// CP2 (0.5): User opened a PIN-related parental controls article, per instrumentation
checkpoints.push({ passed: openedPinIsRelated, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const paymentSettings = JSON.parse(localStorage.getItem('payment_settings_state') || '[]');
const current = paymentSettings[0] || null;

// CP1 (1.0): The primary payment settings record has billing_country set to 'united_states'
const billingUS = !!(current && current.billing_country === 'united_states');
checkpoints.push({ passed: billingUS, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles_state') || '[]');
const searchQueries = JSON.parse(localStorage.getItem('search_queries') || '[]');

// Identify downloads-related billing articles
const downloadsArticles = articles.filter(a => {
  const inBillingSubcat = a.category_code === 'account_billing' && a.subcategory_id === 'payment_methods_charges';
  const text = `${a.title || ''} ${a.summary || ''}`.toLowerCase();
  return inBillingSubcat && text.includes('download');
});

let planDevicesArticle = null;
let comparePlansArticle = null;

downloadsArticles.forEach(a => {
  const title = (a.title || '').toLowerCase();
  if (!planDevicesArticle && title.includes('how many devices can download')) {
    planDevicesArticle = a;
  }
  if (!comparePlansArticle && title.includes('download limits for other plans')) {
    comparePlansArticle = a;
  }
});

// Fallback heuristics if exact matches not found
if (!planDevicesArticle) {
  planDevicesArticle = downloadsArticles.find(a => {
    const t = (a.title || '').toLowerCase();
    return t.includes('how many devices') && t.includes('download');
  }) || null;
}

if (!comparePlansArticle) {
  comparePlansArticle = downloadsArticles.find(a => {
    const t = (a.title || '').toLowerCase();
    return t.includes('download limits') && t.includes('plans');
  }) || null;
}

const savedIds = new Set(saved.map(sa => sa.article_id));
const bothSaved = !!(planDevicesArticle && comparePlansArticle && savedIds.has(planDevicesArticle.id) && savedIds.has(comparePlansArticle.id));

// Check if user used downloads topic + Standard plan filters in search that returned the main devices article
let usedPlanFiltersForMain = false;
if (planDevicesArticle) {
  usedPlanFiltersForMain = searchQueries.some(q => {
    if (!q) return false;
    const hasDownloadsTopic = Array.isArray(q.topic_filter_codes) && q.topic_filter_codes.includes('downloads');
    const hasStandardPlan = Array.isArray(q.plan_filter_codes) && q.plan_filter_codes.includes('standard');
    const hasDownloadWord = typeof q.query_text === 'string' && /download/i.test(q.query_text);
    const includesMainArticle = Array.isArray(q.result_article_ids) && q.result_article_ids.includes(planDevicesArticle.id);
    return hasDownloadsTopic && hasStandardPlan && hasDownloadWord && includesMainArticle;
  });
}

// CP1 (0.6): User saved both the plan-specific downloads devices article and the cross-plan limits article
checkpoints.push({ passed: bothSaved, weight: 0.6 });

// CP2 (0.4): User used downloads + Standard plan filters in a search that surfaced the main plan devices article
checkpoints.push({ passed: !!planDevicesArticle && usedPlanFiltersForMain, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const contactOptions = JSON.parse(localStorage.getItem('contact_options') || '[]');
const supportRequests = JSON.parse(localStorage.getItem('support_requests') || '[]');
const searchQueries = JSON.parse(localStorage.getItem('search_queries') || '[]');

// Identify the VC_201 error article on computers dynamically
const vcArticles = articles.filter(a => {
  const text = `${a.title || ''} ${a.summary || ''}`.toLowerCase();
  const mentionsVC201 = text.includes('vc_201');
  const hasErrorCodeField = (a.default_error_code || '').toUpperCase() === 'VC_201';
  return mentionsVC201 || hasErrorCodeField;
});
const vcArticle = vcArticles[0] || null;

// Determine fastest available contact methods for that article (e.g., chat)
let fastestTypes = new Set();
if (vcArticle) {
  const opts = contactOptions.filter(co => co.article_id === vcArticle.id && co.available !== false);
  if (opts.length > 0) {
    let minWait = Infinity;
    opts.forEach(o => {
      const wait = typeof o.estimated_wait_minutes === 'number' ? o.estimated_wait_minutes : Infinity;
      if (wait < minWait) minWait = wait;
    });
    opts.forEach(o => {
      const wait = typeof o.estimated_wait_minutes === 'number' ? o.estimated_wait_minutes : Infinity;
      if (wait === minWait) fastestTypes.add(o.type);
    });
  }
}

// Find support requests that match this article, fastest contact method, and include VC_201 as error code
let fastestRequestsWithCode = [];
if (vcArticle && fastestTypes.size > 0) {
  fastestRequestsWithCode = supportRequests.filter(r => {
    if (!r) return false;
    if (r.source_article_id !== vcArticle.id) return false;
    if (!fastestTypes.has(r.contact_method)) return false;
    const code = (r.error_code || '').toUpperCase();
    return code === 'VC_201';
  });
}

// Check if user searched for VC_201 and the search results included this article
let searchedVc201 = false;
if (vcArticle) {
  searchedVc201 = searchQueries.some(q => {
    if (!q || typeof q.query_text !== 'string') return false;
    const hasCodeInQuery = /vc_201/i.test(q.query_text);
    const includesArticle = Array.isArray(q.result_article_ids) && q.result_article_ids.includes(vcArticle.id);
    return hasCodeInQuery && includesArticle;
  });
}

// CP1 (0.6): User started a support request from the VC_201 article using the fastest contact method and with error_code 'VC_201'
checkpoints.push({ passed: fastestRequestsWithCode.length > 0, weight: 0.6 });

// CP2 (0.4): User performed a search including VC_201 that returned the VC_201 error article
checkpoints.push({ passed: !!vcArticle && searchedVc201, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
